// =============================================================================
//                         FILE DETAILS
// Project               :
// File                  : lscc_gddr_sync.v
// Title                 :
// Dependencies          : 1.
//                       : 2.
// Description           :rst_i       => Asynchronous reset
//                       :sync_clk_i  => oscillator clk or other constant
//                       :             running low speed clk.
//                       :             note that this clk should not be
//                       :             coming from clk sources
//                       :             that this module will stop_o or reset
//                       :             (e.g. ECLKSYNC, CLKDIV)
//                       :start_i     => Initialize the sync process
//                       :stop_o      => ECLKSYNC.stop_o signal
//                       :ddr_reset_o => DDR and CLKDIV reset signal
//                       :ready_o     => READY signal; clock sync is done.
//
// =============================================================================
//                        REVISION HISTORY
// Version               : 1.0
// Author(s)             :
// Mod. Date             :
// Changes Made          : Initial version.
// =============================================================================
// Version               : 1.0
// Author(s)             : 
// Mod. Date             : 10/07/18
// Changes Made          : Checking coding style.
// =============================================================================
module csi2_transmitter_ip_ipgen_lscc_gddr_sync (
    // -----------------------------------------------------------------------------
    // Input/Output Ports
    // -----------------------------------------------------------------------------
    input wire sync_clk_i, 
    input wire rst_i, 
    input wire start_i, 
    output wire stop_o, 
    output wire ddr_reset_o, 
    output wire ready_o) ;
    // -----------------------------------------------------------------------------
    // Local Parameters
    // -----------------------------------------------------------------------------
    localparam INIT = 3'b000 ; 
    localparam STOP = 3'b001 ; 
    localparam RESET = 3'b011 ; 
    localparam READY = 3'b100 ; 
    // -----------------------------------------------------------------------------
    // Sequential Registers
    // -----------------------------------------------------------------------------
    reg ddr_reset_d ; 
    reg [3:0] ctrl_cnt ; // control counter
    reg [2:0] stop_assert ; // stop_o signal counter
    reg [2:0] cs_gddr_sync ; // current state
    reg [2:0] ns_gddr_sync ; // next state
    reg reset_flag ; // flag signal that
    // indicates that RESET
    // is already done
    //-----------------------------------------------------------------------------
    //  WIRE ASSIGNMENTS
    //-----------------------------------------------------------------------------
    assign stop_o = cs_gddr_sync[0] ; 
    assign ddr_reset_o = (cs_gddr_sync[1] | ddr_reset_d) ; 
    assign ready_o = cs_gddr_sync[2] ; 
    // -----------------------------------------------------------------------------
    // Combinatorial Blocks
    // -----------------------------------------------------------------------------
    // always @(posedge sync_clk_i) begin //avant foundation IP uses synchronous rst_i 
    always
        @(posedge sync_clk_i or 
            posedge rst_i)
        begin
            if ((rst_i == 1'b1)) 
                begin
                    cs_gddr_sync <=  INIT ;
                    ctrl_cnt <=  4'd0 ;
                    stop_assert <=  3'd0 ;
                    reset_flag <=  1'b0 ;
                    ddr_reset_d <=  1'b1 ;
                end
            else
                begin
                    cs_gddr_sync <=  ns_gddr_sync ;
                    ddr_reset_d <=  1'b0 ;
                    if ((((cs_gddr_sync == INIT) && (reset_flag == 1'b0)) || ((ctrl_cnt == 3) && (cs_gddr_sync != INIT)))) 
                        begin
                            ctrl_cnt <=  4'd0 ;
                        end
                    else
                        if ((ctrl_cnt < 8)) 
                            begin
                                ctrl_cnt <=  (ctrl_cnt + 1'b1) ;
                            end
                    if (((((!rst_i) && start_i) && (stop_assert < 4)) && (reset_flag == 1'b0))) 
                        begin
                            stop_assert <=  (stop_assert + 1'b1) ;
                        end
                    if (((cs_gddr_sync == RESET) && (ns_gddr_sync == STOP))) 
                        begin
                            reset_flag <=  1'b1 ;
                        end
                    if (((cs_gddr_sync == READY) && (ns_gddr_sync == INIT))) 
                        begin
                            reset_flag <=  1'b0 ;
                        end
                end
        end
    always
        @(*)
        begin
            case (cs_gddr_sync)
            INIT : 
                begin
                    if (((start_i && (stop_assert == 3)) && (reset_flag == 1'b0))) 
                        begin
                            ns_gddr_sync = STOP ;
                        end
                    else
                        if ((((reset_flag == 1'b1) && (ctrl_cnt == 7)) && start_i)) 
                            begin
                                ns_gddr_sync = READY ;
                            end
                        else
                            begin
                                ns_gddr_sync = INIT ;
                            end
                end
            STOP : 
                begin
                    if ((ctrl_cnt == 3)) 
                        begin
                            if ((reset_flag == 1'b1)) 
                                begin
                                    ns_gddr_sync = INIT ;
                                end
                            else
                                begin
                                    ns_gddr_sync = RESET ;
                                end
                        end
                    else
                        begin
                            ns_gddr_sync = STOP ;
                        end
                end
            RESET : 
                begin
                    if ((ctrl_cnt == 3)) 
                        begin
                            ns_gddr_sync = STOP ;
                        end
                    else
                        begin
                            ns_gddr_sync = RESET ;
                        end
                end
            READY : 
                begin
                    if ((!start_i)) 
                        begin
                            ns_gddr_sync = INIT ;
                        end
                    else
                        begin
                            ns_gddr_sync = READY ;
                        end
                end
            default : 
                begin
                    ns_gddr_sync = cs_gddr_sync ;
                end
            endcase 
        end
endmodule



