    output wire lp_rx_data_n_o, 
    // Other signals
    input wire pd_dphy_i, 
    output wire pll_lock_o, 
    output wire clk_byte_o, 
    output wire ready_o, 
    // DPHY signals
    inout wire clk_p_io, 
    inout wire clk_n_io, 
    inout wire [(NUM_LANE - 1):0] data_p_io, 
    inout wire [(NUM_LANE - 1):0] data_n_io) ;
