    wire gddr_reset_w ; 
    wire eclkdiv_clk_4data_w ; 
    wire eclkdiv_clk_4clk_w ; 
    wire clk_dif_w ; // from DELAYA to MIPI
    wire clk_dif_w_oddr ; // from ODDR to DELAYA
    wire [(NUM_LANE - 1):0] data_dif_w ; 
    wire [(NUM_LANE - 1):0] lp_rx_data_p_w ; 
    wire [(NUM_LANE - 1):0] lp_rx_data_n_w ; 
    // -----------------------------------------------------------------------------
    // Register  Declarations
    // -----------------------------------------------------------------------------
    //output of the serializer (ODDRX4) is delayed by 3 SCLKs
    //must delay the lp/hs enable signals going to the MIPI IO to compensate for the delay of the HS-DATA/HS-CLK
    reg lp_tx_clk_p_q0 ; 
    reg lp_tx_clk_p_q1 ; 
    reg lp_tx_clk_p_q2 ; 
    reg lp_tx_clk_n_q0 ; 
    reg lp_tx_clk_n_q1 ; 
    reg lp_tx_clk_n_q2 ; 
    reg hs_tx_clk_en_q0 ; 
    reg hs_tx_clk_en_q1 ; 
    reg hs_tx_clk_en_q2 ; 
    reg [(NUM_LANE - 1):0] lp_tx_data_p_q0 ; 
    reg [(NUM_LANE - 1):0] lp_tx_data_p_q1 ; 
    reg [(NUM_LANE - 1):0] lp_tx_data_p_q2 ; 
    reg [(NUM_LANE - 1):0] lp_tx_data_n_q0 ; 
    reg [(NUM_LANE - 1):0] lp_tx_data_n_q1 ; 
    reg [(NUM_LANE - 1):0] lp_tx_data_n_q2 ; 
    reg lp_tx_data_en_q0 ; 
    reg lp_tx_data_en_q1 ; 
    reg lp_tx_data_en_q2 ; 
    reg hs_tx_en_q0 ; 
    reg hs_tx_en_q1 ; 
    reg hs_tx_en_q2 ; 
    // -----------------------------------------------------------------------------
    // Assign Statements
    // -----------------------------------------------------------------------------
    assign lp_rx_data_p_o = lp_rx_data_p_w[0] ; 
    assign lp_rx_data_n_o = lp_rx_data_n_w[0] ; 
    assign clk_byte_o = eclkdiv_clk_4data_w ; //eclkdiv_clk_4clk_w;
    assign pll_lock_o = ready_o ; 
    ///////////////////////////////////////////////////////////////////////////////
    /// PLL
    ///////////////////////////////////////////////////////////////////////////////
    generate
        if ((PLL_MODE == "INTERNAL")) 
            begin : INTERNAL_PLL
                csi2_transmitter_ip_ipgen_lscc_pll #(.MODE(MODE),
                        .IPI_CMP(IPI_CMP),
                        .VOLTAGE(VOLTAGE),
                        .CSET(CSET),
                        .CRIPPLE(CRIPPLE),
                        .IPP_CTRL(IPP_CTRL),
                        .IPP_SEL(IPP_SEL),
                        .BW_CTL_BIAS(BW_CTL_BIAS),
                        .V2I_PP_RES(V2I_PP_RES),
                        .KP_VCO(KP_VCO),
                        .V2I_KVCO_SEL(V2I_KVCO_SEL),
                        .V2I_1V_EN(V2I_1V_EN),
                        .CLKI_FREQ(CLKI_FREQ),
                        .CLKOP_FREQ_ACTUAL(CLKOP_FREQ_ACTUAL),
                        .CLKOS_FREQ_ACTUAL(CLKOS_FREQ_ACTUAL),
                        .CLKOS2_FREQ_ACTUAL(CLKOS2_FREQ_ACTUAL),
                        .CLKOS3_FREQ_ACTUAL(CLKOS3_FREQ_ACTUAL),
                        .CLKOS4_FREQ_ACTUAL(CLKOS4_FREQ_ACTUAL),
                        .CLKOS5_FREQ_ACTUAL(CLKOS5_FREQ_ACTUAL),
                        .CLKOP_PHASE_ACTUAL(CLKOP_PHASE_ACTUAL),
                        .CLKOS_PHASE_ACTUAL(CLKOS_PHASE_ACTUAL),
                        .CLKOS2_PHASE_ACTUAL(CLKOS2_PHASE_ACTUAL),
                        .CLKOS3_PHASE_ACTUAL(CLKOS3_PHASE_ACTUAL),
                        .CLKOS4_PHASE_ACTUAL(CLKOS4_PHASE_ACTUAL),
                        .CLKOS5_PHASE_ACTUAL(CLKOS5_PHASE_ACTUAL),
                        .PLL_REFCLK_FROM_PIN(PLL_REFCLK_FROM_PIN),
                        .IO_TYPE(IO_TYPE),
                        .CLKI_DIVIDER_ACTUAL_STR(CLKI_DIVIDER_ACTUAL_STR),
                        .FBCLK_DIVIDER_ACTUAL_STR(FBCLK_DIVIDER_ACTUAL_STR),
                        .FBK_MODE(FBK_MODE),
                        .DIVOP_ACTUAL_STR(DIVOP_ACTUAL_STR),
                        .DIVOS_ACTUAL_STR(DIVOS_ACTUAL_STR),
                        .DIVOS2_ACTUAL_STR(DIVOS2_ACTUAL_STR),
                        .DIVOS3_ACTUAL_STR(DIVOS3_ACTUAL_STR),
                        .DIVOS4_ACTUAL_STR(DIVOS4_ACTUAL_STR),
                        .DIVOS5_ACTUAL_STR(DIVOS5_ACTUAL_STR),
                        .SSC_N_CODE_STR(SSC_N_CODE_STR),
                        .SSC_F_CODE_STR(SSC_F_CODE_STR),
                        .DELA(DELA),
                        .DELB(DELB),
                        .DELC(DELC),
                        .DELD(DELD),
                        .DELE(DELE),
                        .DELF(DELF),
                        .PHIA(PHIA),
                        .PHIB(PHIB),
                        .PHIC(PHIC),
                        .PHID(PHID),
                        .PHIE(PHIE),
                        .PHIF(PHIF),
                        .FRAC_N_EN(FRAC_N_EN),
                        .SS_EN(SS_EN),
                        .CLKOP_BYPASS(CLKOP_BYPASS),
                        .CLKOS_BYPASS(CLKOS_BYPASS),
                        .CLKOS2_BYPASS(CLKOS2_BYPASS),
                        .CLKOS3_BYPASS(CLKOS3_BYPASS),
                        .CLKOS4_BYPASS(CLKOS4_BYPASS),
                        .CLKOS5_BYPASS(CLKOS5_BYPASS),
                        .CLKOS_EN(CLKOS_EN),
                        .CLKOS2_EN(CLKOS2_EN),
                        .CLKOS3_EN(CLKOS3_EN),
                        .CLKOS4_EN(CLKOS4_EN),
                        .CLKOS5_EN(CLKOS5_EN),
                        .DYN_PORTS_EN(DYN_PORTS_EN),
                        .ENCLKOP_EN(ENCLKOP_EN),
                        .ENCLKOS_EN(ENCLKOS_EN),
                        .ENCLKOS2_EN(ENCLKOS2_EN),
                        .ENCLKOS3_EN(ENCLKOS3_EN),
                        .ENCLKOS4_EN(ENCLKOS4_EN),
                        .ENCLKOS5_EN(ENCLKOS5_EN),
                        .PLL_RST(PLL_RST),
                        .LOCK_EN(LOCK_EN),
                        .PLL_LOCK_STICKY(PLL_LOCK_STICKY),
                        .LEGACY_EN(LEGACY_EN),
                        .LMMI_EN(LMMI_EN),
                        .APB_EN(APB_EN),
                        .POWERDOWN_EN(POWERDOWN_EN),
                        .TRIM_EN_P(TRIM_EN_P),
                        .TRIM_EN_S(TRIM_EN_S),
                        .CLKOP_TRIM_MODE(CLKOP_TRIM_MODE),
                        .CLKOS_TRIM_MODE(CLKOS_TRIM_MODE),
                        .CLKOP_TRIM(CLKOP_TRIM),
                        .CLKOS_TRIM(CLKOS_TRIM)) u_pll (.clki_i(sync_clk_i), 
                            .rstn_i(((!sync_rst_i) | pll_reset_i)), 
                            .legacy_i(1'b1), 
                            .pllpd_en_n_i(1'b0), 
                            .phasedir_i(1'b1), 
                            .phasestep_i(1'b1), 
                            .phaseloadreg_i(1'b1), 
                            .phasesel_i(3'b111), 
                            .enclkop_i(1'b1), 
                            .enclkos_i(1'b1), 
                            .enclkos2_i(1'b1), 
                            .enclkos3_i(1'b1), 
                            .enclkos4_i(1'b1), 
                            .enclkos5_i(1'b1), 
                            .clkop_o(pll_clkop_w), 
                            .clkos_o(), 
                            .clkos2_o(), 
                            .clkos3_o(), 
                            .clkos4_o(), 
                            .clkos5_o(), 
                            .lock_o(pll_lock_w), 
                            .lmmi_clk_i(1'b1), 
                            .lmmi_resetn_i(1'b1), 
                            .lmmi_request_i(1'b1), 
                            .lmmi_wr_rdn_i(1'b1), 
                            .lmmi_offset_i(7'b1111111), 
                            .lmmi_wdata_i(8'b11111111), 
                            .lmmi_rdata_o(), 
                            .lmmi_rdata_valid_o(), 
                            .lmmi_ready_o(), 
                            .apb_penable_i(1'b0), 
                            .apb_psel_i(1'b0), 
                            .apb_pwrite_i(1'b0), 
                            .apb_paddr_i(7'b0000000), 
                            .apb_pwdata_i(8'b00000000), 
                            .apb_pready_o(), 
                            .apb_pslverr_o(), 
                            .apb_prdata_o()) ; 
            end
        else
            begin : EXTERNAL_PLL
                assign pll_clkop_w = pll_clkop_i ; 
                assign pll_lock_w = pll_lock_i ; 
            end
    endgenerate
    ///////////////////////////////////////////////////////////////////////////////
    /// Clock Divider for data and diff. clock, gddr_sync
    ///////////////////////////////////////////////////////////////////////////////
    ECLKSYNC #(.STOP_EN("ENABLE")) u_eclksync_core_4data (.ECLKIN(pll_clkop_w), 
                .STOP(gddr_stop_w), 
                .ECLKOUT(eclksync_clk_w)) ; 
    ECLKDIV #(.ECLK_DIV("4"),
            .GSR("DISABLED")) u_eclkdiv_4data (.DIVRST(gddr_reset_w), 
                .ECLKIN(eclksync_clk_w), 
                .SLIP(pd_dphy_i), 
                .DIVOUT(eclkdiv_clk_4data_w)) ; 
    csi2_transmitter_ip_ipgen_lscc_gddr_sync u_gddr_sync (.sync_clk_i(sync_clk_i), 
                .rst_i(sync_rst_i), 
                .start_i(pll_lock_w), 
                .stop_o(gddr_stop_w), 
                .ddr_reset_o(gddr_reset_w), 
                .ready_o(ready_o)) ; 
    //output of the serializer (ODDRX4) is delayed by 3 SCLKs
    //must delay the lp/hs enable signals going to the MIPI IO to compensate for the delay of the HS-DATA/HS-CLK
    always
        @(posedge clk_byte_o or 
            negedge reset_n_i)
        begin
            if ((!reset_n_i)) 
                begin
                    lp_tx_clk_p_q0 <=  1'b1 ;
                    lp_tx_clk_p_q1 <=  1'b1 ;
                    lp_tx_clk_p_q2 <=  1'b1 ;
                    lp_tx_clk_n_q0 <=  1'b1 ;
                    lp_tx_clk_n_q1 <=  1'b1 ;
                    lp_tx_clk_n_q2 <=  1'b1 ;
                    hs_tx_clk_en_q0 <=  1'b0 ;
                    hs_tx_clk_en_q1 <=  1'b0 ;
                    hs_tx_clk_en_q2 <=  1'b0 ;
                    lp_tx_data_p_q0 <=  {NUM_LANE{1'b1}} ;
                    lp_tx_data_p_q1 <=  {NUM_LANE{1'b1}} ;
                    lp_tx_data_p_q2 <=  {NUM_LANE{1'b1}} ;
                    lp_tx_data_n_q0 <=  {NUM_LANE{1'b1}} ;
                    lp_tx_data_n_q1 <=  {NUM_LANE{1'b1}} ;
                    lp_tx_data_n_q2 <=  {NUM_LANE{1'b1}} ;
                    lp_tx_data_en_q0 <=  1'b1 ;
                    lp_tx_data_en_q1 <=  1'b1 ;
                    lp_tx_data_en_q2 <=  1'b1 ;
                    hs_tx_en_q0 <=  1'b0 ;
                    hs_tx_en_q1 <=  1'b0 ;
                    hs_tx_en_q2 <=  1'b0 ;
                end
            else
                begin
                    lp_tx_clk_p_q0 <=  lp_tx_clk_p_i ;
                    lp_tx_clk_p_q1 <=  lp_tx_clk_p_q0 ;
                    lp_tx_clk_p_q2 <=  lp_tx_clk_p_q1 ;
                    lp_tx_clk_n_q0 <=  lp_tx_clk_n_i ;
                    lp_tx_clk_n_q1 <=  lp_tx_clk_n_q0 ;
                    lp_tx_clk_n_q2 <=  lp_tx_clk_n_q1 ;
                    hs_tx_clk_en_q0 <=  hs_tx_clk_en_i ;
                    hs_tx_clk_en_q1 <=  hs_tx_clk_en_q0 ;
                    hs_tx_clk_en_q2 <=  hs_tx_clk_en_q1 ;
                    lp_tx_data_p_q0 <=  lp_tx_data_p_i ;
                    lp_tx_data_p_q1 <=  lp_tx_data_p_q0 ;
                    lp_tx_data_p_q2 <=  lp_tx_data_p_q1 ;
                    lp_tx_data_n_q0 <=  lp_tx_data_n_i ;
                    lp_tx_data_n_q1 <=  lp_tx_data_n_q0 ;
                    lp_tx_data_n_q2 <=  lp_tx_data_n_q1 ;
                    lp_tx_data_en_q0 <=  lp_tx_data_en_i ;
                    lp_tx_data_en_q1 <=  lp_tx_data_en_q0 ;
                    lp_tx_data_en_q2 <=  lp_tx_data_en_q1 ;
                    hs_tx_en_q0 <=  hs_tx_en_i ;
                    hs_tx_en_q1 <=  hs_tx_en_q0 ;
                    hs_tx_en_q2 <=  hs_tx_en_q1 ;
                end
        end
    ///////////////////////////////////////////////////////////////////////////////
    /// Clock
    ///////////////////////////////////////////////////////////////////////////////
    ODDRX4 #(.GSR("DISABLED")) u_clk_serializer (.Q(clk_dif_w_oddr), 
                .SCLK(eclkdiv_clk_4data_w), 
                .RST(gddr_reset_w), 
                .ECLK(pll_clkos_i), 
                .D0((hs_clk_zero_en_i ? 1'd0 : 1'd1)), 
                .D1((hs_clk_zero_en_i ? 1'd0 : 1'd0)), 
                .D2((hs_clk_zero_en_i ? 1'd0 : 1'd1)), 
                .D3((hs_clk_zero_en_i ? 1'd0 : 1'd0)), 
                .D4((hs_clk_zero_en_i ? 1'd0 : 1'd1)), 
                .D5((hs_clk_zero_en_i ? 1'd0 : 1'd0)), 
                .D6((hs_clk_zero_en_i ? 1'd0 : 1'd1)), 
                .D7((hs_clk_zero_en_i ? 1'd0 : 1'd0))) ; 
    ///  DELAYB #(.DEL_VALUE(DELAYB_DEL_VALUE),
    ///             .COARSE_DELAY(DELAYB_COARSE_DELAY),
    ///             .DEL_MODE(DELAYB_DEL_MODE)) u_clk_90deg_delay (.A(clk_dif_w_oddr), 
    ///             .Z(clk_dif_w)) ;   
    /// DELAYA #(
    ///   .COARSE_DELAY           ("0NS"),          // DATA_COARSE_DELAY_VALUE),
    ///   .DEL_VALUE              ("0"),            // DATA_FINE_DELAY_VALUE),
    ///   .EDGE_MONITOR           ("DISABLED"),
    ///   .WAIT_FOR_EDGE          ("DISABLED"),
    ///   .DEL_MODE               ("USER_DEFINED"),
    ///   .COARSE_DELAY_MODE      ("STATIC")        // "DYNAMIC"))
    /// ) 
    /// u_DELAYA_clk (
    /// // Inputs
    ///   .A                     (clk_dif_w_oddr ), 
    ///   .LOAD_N                (d_loadn),          
    ///   .MOVE                  (d_move), 
    ///   .DIRECTION             (d_dir), 
    ///   .COARSE0               (1'b0), 
    ///   .COARSE1               (1'b0), 
    ///   .RANKENABLE            (1'b0), 
    ///   .RANKSELECT            (1'b0), 
    ///   .RANK0UPDATE           (1'b0), 
    ///   .RANK1UPDATE           (1'b0), 
    /// // Outputs               
    ///   .Z                     (clk_dif_w), 
    ///   .EDETERR               (), 
    ///   .CFLAG                 (d_cflag)) ;      
    MIPI #(.MIPI_ID("0")) u_mipi_clk (.AP(lp_tx_clk_p_q2), 
                .AN(lp_tx_clk_n_q2), 
                .TP(hs_tx_clk_en_q2), 
                .TN(hs_tx_clk_en_q2),  // UCSIP-1362. was 1'b0 for IP v1.4.0 and older.
            .IHS(clk_dif_w_oddr),  //  clk_dif_w
            .HSRXEN(1'd0), 
                .HSTXEN(hs_tx_clk_en_q2), 
                ///
            .OHS(), 
                .OLSP(), 
                .OLSN(), 
                ///
            .BP(clk_p_io), 
                .BN(clk_n_io)) ; 
    ///////////////////////////////////////////////////////////////////////////////
    /// Data
    ///////////////////////////////////////////////////////////////////////////////
    genvar i ; 
    generate
        for (i = 0;(i < NUM_LANE);i = (i + 1))
        begin : DATA_LINES
            ///
            ///
            ODDRX4 #(.GSR("DISABLED")) u_data_serializer (.Q(data_dif_w[i]), 
                        .SCLK(eclkdiv_clk_4data_w), 
                        .RST(gddr_reset_w), 
                        .ECLK(eclksync_clk_w), 
                        .D0(hs_tx_data_i[((i * GEAR) + 0)]), 
                        .D1(hs_tx_data_i[((i * GEAR) + 1)]), 
                        .D2(hs_tx_data_i[((i * GEAR) + 2)]), 
                        .D3(hs_tx_data_i[((i * GEAR) + 3)]), 
                        .D4(hs_tx_data_i[((i * GEAR) + 4)]), 
                        .D5(hs_tx_data_i[((i * GEAR) + 5)]), 
                        .D6(hs_tx_data_i[((i * GEAR) + 6)]), 
                        .D7(hs_tx_data_i[((i * GEAR) + 7)])) ; 
            MIPI #(.MIPI_ID("0")) u_mipi_data (.AP(((i == 0) ? (lp_tx_data_p_q2[i] & (!lp_rx_en_i)) : lp_tx_data_p_q2[i])), 
                        .AN(((i == 0) ? (lp_tx_data_n_q2[i] & (!lp_rx_en_i)) : lp_tx_data_n_q2[i])), 
                        .TP(((hs_tx_en_q2 & (~lp_tx_data_en_q2)) | lp_rx_en_i)), 
                        .TN(((hs_tx_en_q2 & (~lp_tx_data_en_q2)) | lp_rx_en_i)),  // [JAS] UCSIP-1006. was 1'b0 for IP versions older than v1.3.0
                    .IHS(data_dif_w[i]), 
                        .HSRXEN(1'd0), 
                        .HSTXEN(hs_tx_en_q2), 
                        ///
                    .OHS(), 
                        .OLSP(lp_rx_data_p_w[i]), 
                        .OLSN(lp_rx_data_n_w[i]), 
                        ///
                    .BP(data_p_io[i]), 
                        .BN(data_n_io[i])) ; 
        end
    endgenerate
endmodule



