// Changes Made          : Ported to Radiant 2.265.
// =============================================================================
module csi2_transmitter_ip_ipgen_lscc_mipi_dphy_soft_tx_avant #(parameter DEVICE = "LAV-AT-500E", 
        parameter GEAR = 8, 
        parameter NUM_LANE = 1, 
        parameter PLL_MODE = "EXTERNAL", 
        parameter DELAYB_DEL_VALUE = "0", 
        parameter DELAYB_COARSE_DELAY = "0NS", 
        parameter DELAYB_DEL_MODE = "NO_REG", 
        parameter MODE = 0, 
        parameter IPI_CMP = 0, 
        parameter VOLTAGE = 0, 
        parameter CSET = 0, 
        parameter CRIPPLE = 0, 
        parameter IPP_CTRL = 0, 
        parameter IPP_SEL = 0, 
        parameter BW_CTL_BIAS = 0, 
        parameter V2I_PP_RES = 0, 
        parameter KP_VCO = 0, 
        parameter V2I_KVCO_SEL = 0, 
        parameter V2I_1V_EN = 0, 
        parameter CLKI_FREQ = 0, 
        parameter CLKOP_FREQ_ACTUAL = 0, 
        parameter CLKOS_FREQ_ACTUAL = 0, 
        parameter CLKOS2_FREQ_ACTUAL = 0, 
        parameter CLKOS3_FREQ_ACTUAL = 0, 
        parameter CLKOS4_FREQ_ACTUAL = 0, 
        parameter CLKOS5_FREQ_ACTUAL = 0, 
        parameter CLKOP_PHASE_ACTUAL = 0, 
        parameter CLKOS_PHASE_ACTUAL = 0, 
        parameter CLKOS2_PHASE_ACTUAL = 0, 
        parameter CLKOS3_PHASE_ACTUAL = 0, 
        parameter CLKOS4_PHASE_ACTUAL = 0, 
        parameter CLKOS5_PHASE_ACTUAL = 0, 
        parameter PLL_REFCLK_FROM_PIN = 0, 
        parameter IO_TYPE = 0, 
        parameter CLKI_DIVIDER_ACTUAL_STR = 0, 
        parameter FBCLK_DIVIDER_ACTUAL_STR = 0, 
        parameter FBK_MODE = 0, 
        parameter DIVOP_ACTUAL_STR = 0, 
        parameter DIVOS_ACTUAL_STR = 0, 
        parameter DIVOS2_ACTUAL_STR = 0, 
        parameter DIVOS3_ACTUAL_STR = 0, 
        parameter DIVOS4_ACTUAL_STR = 0, 
        parameter DIVOS5_ACTUAL_STR = 0, 
        parameter SSC_N_CODE_STR = 0, 
        parameter SSC_F_CODE_STR = 0, 
        parameter DELA = 0, 
        parameter DELB = 0, 
        parameter DELC = 0, 
        parameter DELD = 0, 
        parameter DELE = 0, 
        parameter DELF = 0, 
        parameter PHIA = 0, 
        parameter PHIB = 0, 
        parameter PHIC = 0, 
        parameter PHID = 0, 
        parameter PHIE = 0, 
        parameter PHIF = 0, 
        parameter FRAC_N_EN = 0, 
        parameter SS_EN = 0, 
        parameter CLKOP_BYPASS = 0, 
        parameter CLKOS_BYPASS = 0, 
        parameter CLKOS2_BYPASS = 0, 
        parameter CLKOS3_BYPASS = 0, 
        parameter CLKOS4_BYPASS = 0, 
        parameter CLKOS5_BYPASS = 0, 
        parameter CLKOS_EN = 0, 
        parameter CLKOS2_EN = 0, 
        parameter CLKOS3_EN = 0, 
        parameter CLKOS4_EN = 0, 
        parameter CLKOS5_EN = 0, 
        parameter DYN_PORTS_EN = 0, 
        parameter ENCLKOP_EN = 0, 
        parameter ENCLKOS_EN = 0, 
        parameter ENCLKOS2_EN = 0, 
        parameter ENCLKOS3_EN = 0, 
        parameter ENCLKOS4_EN = 0, 
        parameter ENCLKOS5_EN = 0, 
        parameter PLL_RST = 0, 
        parameter LOCK_EN = 0, 
        parameter PLL_LOCK_STICKY = 0, 
        parameter LEGACY_EN = 0, 
        parameter LMMI_EN = 0, 
        parameter APB_EN = 0, 
        parameter POWERDOWN_EN = 0, 
        parameter TRIM_EN_P = 0, 
        parameter TRIM_EN_S = 0, 
        parameter CLKOP_TRIM_MODE = 0, 
        parameter CLKOS_TRIM_MODE = 0, 
        parameter CLKOP_TRIM = 0, 
        parameter CLKOS_TRIM = 0) (
    // -----------------------------------------------------------------------------
    // Module Parameters
    // -----------------------------------------------------------------------------
    /// DELAYB
    /// Soft PLL
    // -----------------------------------------------------------------------------
    // Input/Output Ports
    // -----------------------------------------------------------------------------
    // Clock and reset
    input wire sync_clk_i, 
    input wire sync_rst_i, 
    input wire reset_n_i,  //for clk_byte_o
    input wire pll_reset_i, 
    // PLL outside of the Soft IP
    input wire pll_clkop_i, 
    input wire pll_clkos_i, 
    input wire pll_lock_i, 
    // HS_TX signals
    input wire hs_tx_en_i, 
    input wire hs_tx_clk_en_i, 
    input wire [((GEAR * NUM_LANE) - 1):0] hs_tx_data_i, 
    input wire hs_clk_zero_en_i, 
    // LP_TX signals
    input wire [(NUM_LANE - 1):0] lp_tx_data_p_i, 
    input wire [(NUM_LANE - 1):0] lp_tx_data_n_i, 
    input wire lp_tx_data_en_i, 
    input wire lp_tx_clk_p_i, 
    input wire lp_tx_clk_n_i, 
    // LP_RX signals
    input wire lp_rx_en_i, 
    output wire lp_rx_data_p_o, 
    output wire lp_rx_data_n_o, 
    // Other signals
    input wire pd_dphy_i, 
    output wire pll_lock_o, 
    output wire clk_byte_o, 
    output wire ready_o, 
    // DPHY signals
    inout wire clk_p_io, 
    inout wire clk_n_io, 
    inout wire [(NUM_LANE - 1):0] data_p_io, 
    inout wire [(NUM_LANE - 1):0] data_n_io) ;
    // -----------------------------------------------------------------------------
    // Wire Declarations
    // -----------------------------------------------------------------------------
    wire pll_clkop_w ; 
    wire pll_clkos_w ; 
    wire pll_lock_w ; 
    wire gddr_stop_w ; 
    wire eclksync_clk_w ; 
    wire eclksync_clk_w1 ; 
    wire gddr_reset_w ; 
    wire eclkdiv_clk_4data_w ; 
    wire eclkdiv_clk_4clk_w ; 
    wire clk_dif_w ; 
    wire [(NUM_LANE - 1):0] data_dif_w ; 
    wire [(NUM_LANE - 1):0] lp_rx_data_p_w ; 
    wire [(NUM_LANE - 1):0] lp_rx_data_n_w ; 
    // -----------------------------------------------------------------------------
    // Assign Statements
    // -----------------------------------------------------------------------------
    assign lp_rx_data_p_o = lp_rx_data_p_w[0] ; 
    assign lp_rx_data_n_o = lp_rx_data_n_w[0] ; 
    assign clk_byte_o = eclkdiv_clk_4data_w ; //eclkdiv_clk_4clk_w;
    assign pll_lock_o = ready_o ; 
    ///////////////////////////////////////////////////////////////////////////////
    /// PLL
    ///////////////////////////////////////////////////////////////////////////////
    assign pll_clkop_w = pll_clkop_i ; 
    assign pll_clkos_w = pll_clkos_i ; 
    assign pll_lock_w = pll_lock_i ; 
    generate
        if ((DEVICE == "LAV-AT-500E")) 
            begin : AVANTE_SOFT_TX
                // ================== AVANT-E ==================== //
                ECLKSYNC u0_ECLKSYNC (.ECLKIN(pll_clkop_w), 
                            .SYNC(gddr_stop_w), 
                            .RST(1'b0), 
                            .ECLKOUT(eclksync_clk_w)) ; 
                ECLKDIV #(.CLK_DIV("4"),
                        .ALIGN("ENABLED"),
                        .RATE("HALF"),
                        .PHYBY4_SEL("DISABLED"),
                        .GSR("DISABLED")) u_eclkdiv_4data (.RST(gddr_reset_w), 
                            .ECLKIN(eclksync_clk_w), 
                            .ALIGNWD(pd_dphy_i), 
                            .ECLKDIVOUT(eclkdiv_clk_4data_w) // eclkdiv_clk_w
                        ) ; 
            end
        else
            begin : AVANTGX_SOFT_TX
                // ================== AVANT ==================== //
                ECLKSYNCA u0_ECLKSYNC (.ECLKIN(pll_clkop_w), 
                            .SYNC(gddr_stop_w), 
                            .RST(1'b0), 
                            .ECLKOUT(eclksync_clk_w)) ; 
                ECLKDIVA #(.CLK_DIV("4"),
                        .ALIGN("ENABLED"),
                        .RATE("HALF"),
                        .PHYBY4_SEL("DISABLED"),
                        .GSR("DISABLED")) u_eclkdiv_4data (.RST(gddr_reset_w), 
                            .ECLKIN(eclksync_clk_w), 
                            .ALIGNWD(pd_dphy_i), 
                            .ECLKDIVOUT(eclkdiv_clk_4data_w) // eclkdiv_clk_w
                        ) ; 
            end
    endgenerate
    // ================== AVANT ==================== //
    csi2_transmitter_ip_ipgen_lscc_gddr_sync u_gddr_sync (.sync_clk_i(sync_clk_i), 
                .rst_i(sync_rst_i), 
                .start_i(pll_lock_w), 
                .stop_o(gddr_stop_w), 
                .ddr_reset_o(gddr_reset_w), 
                .ready_o(ready_o)) ; 
    //output of the serializer (ODDRX4) is delayed by 3 SCLKs
    //must delay the lp/hs enable signals going to the MIPI IO to compensate for the delay of the HS-DATA/HS-CLK
    reg lp_tx_clk_p_q0 ; 
    reg lp_tx_clk_p_q1 ; 
    reg lp_tx_clk_p_q2 ; 
    reg lp_tx_clk_n_q0 ; 
    reg lp_tx_clk_n_q1 ; 
    reg lp_tx_clk_n_q2 ; 
    reg hs_tx_clk_en_q0 ; 
    reg hs_tx_clk_en_q1 ; 
    reg hs_tx_clk_en_q2 ; 
    reg [(NUM_LANE - 1):0] lp_tx_data_p_q0 ; 
    reg [(NUM_LANE - 1):0] lp_tx_data_p_q1 ; 
    reg [(NUM_LANE - 1):0] lp_tx_data_p_q2 ; 
    reg [(NUM_LANE - 1):0] lp_tx_data_n_q0 ; 
    reg [(NUM_LANE - 1):0] lp_tx_data_n_q1 ; 
    reg [(NUM_LANE - 1):0] lp_tx_data_n_q2 ; 
    reg lp_tx_data_en_q0 ; 
    reg lp_tx_data_en_q1 ; 
    reg lp_tx_data_en_q2 ; 
    reg hs_tx_en_q0 ; 
    reg hs_tx_en_q1 ; 
    reg hs_tx_en_q2 ; 
    reg clk_crialzr_rst ; 
    always
        @(posedge clk_byte_o or 
            negedge reset_n_i)
        begin
            if ((!reset_n_i)) 
                begin
                    lp_tx_clk_p_q0 <=  1'b1 ;
                    lp_tx_clk_p_q1 <=  1'b1 ;
                    lp_tx_clk_p_q2 <=  1'b1 ;
                    lp_tx_clk_n_q0 <=  1'b1 ;
                    lp_tx_clk_n_q1 <=  1'b1 ;
                    lp_tx_clk_n_q2 <=  1'b1 ;
                    hs_tx_clk_en_q0 <=  1'b0 ;
                    hs_tx_clk_en_q1 <=  1'b0 ;
                    hs_tx_clk_en_q2 <=  1'b0 ;
                    lp_tx_data_p_q0 <=  {NUM_LANE{1'b1}} ;
                    lp_tx_data_p_q1 <=  {NUM_LANE{1'b1}} ;
                    lp_tx_data_p_q2 <=  {NUM_LANE{1'b1}} ;
                    lp_tx_data_n_q0 <=  {NUM_LANE{1'b1}} ;
                    lp_tx_data_n_q1 <=  {NUM_LANE{1'b1}} ;
                    lp_tx_data_n_q2 <=  {NUM_LANE{1'b1}} ;
                    lp_tx_data_en_q0 <=  1'b1 ;
                    lp_tx_data_en_q1 <=  1'b1 ;
                    lp_tx_data_en_q2 <=  1'b1 ;
                    hs_tx_en_q0 <=  1'b0 ;
                    hs_tx_en_q1 <=  1'b0 ;
                    hs_tx_en_q2 <=  1'b0 ;
                    clk_crialzr_rst <=  1'b0 ;
                end
            else
                begin
                    lp_tx_clk_p_q0 <=  lp_tx_clk_p_i ;
                    lp_tx_clk_p_q1 <=  lp_tx_clk_p_q0 ;
                    lp_tx_clk_p_q2 <=  lp_tx_clk_p_q1 ;
                    lp_tx_clk_n_q0 <=  lp_tx_clk_n_i ;
                    lp_tx_clk_n_q1 <=  lp_tx_clk_n_q0 ;
                    lp_tx_clk_n_q2 <=  lp_tx_clk_n_q1 ;
                    hs_tx_clk_en_q0 <=  hs_tx_clk_en_i ;
                    hs_tx_clk_en_q1 <=  hs_tx_clk_en_q0 ;
                    hs_tx_clk_en_q2 <=  hs_tx_clk_en_q1 ;
                    lp_tx_data_p_q0 <=  lp_tx_data_p_i ;
                    lp_tx_data_p_q1 <=  lp_tx_data_p_q0 ;
                    lp_tx_data_p_q2 <=  lp_tx_data_p_q1 ;
                    lp_tx_data_n_q0 <=  lp_tx_data_n_i ;
                    lp_tx_data_n_q1 <=  lp_tx_data_n_q0 ;
                    lp_tx_data_n_q2 <=  lp_tx_data_n_q1 ;
                    lp_tx_data_en_q0 <=  lp_tx_data_en_i ;
                    lp_tx_data_en_q1 <=  lp_tx_data_en_q0 ;
                    lp_tx_data_en_q2 <=  lp_tx_data_en_q1 ;
                    hs_tx_en_q0 <=  hs_tx_en_i ;
                    hs_tx_en_q1 <=  hs_tx_en_q0 ;
                    hs_tx_en_q2 <=  hs_tx_en_q1 ;
                    clk_crialzr_rst <=  (gddr_reset_w || (!hs_tx_clk_en_i)) ;// high asserted
                end
        end
    ///////////////////////////////////////////////////////////////////////////////
    /// Clock
    ///////////////////////////////////////////////////////////////////////////////
    // ================== AVANT ==================== //
    ODDRX4A #(.GSR("DISABLED")) u_clk_serializer (.Q(clk_dif_w), 
                .SCLK(eclkdiv_clk_4data_w),  // from u_eclkdiv_4data
            .RST(clk_crialzr_rst),  // (gddr_reset_w),
            .ECLK(pll_clkos_w),  // from pll_os_90shift
            .D0((hs_clk_zero_en_i ? 1'd0 : 1'd1)), 
                .D1((hs_clk_zero_en_i ? 1'd0 : 1'd0)), 
                .D2((hs_clk_zero_en_i ? 1'd0 : 1'd1)), 
                .D3((hs_clk_zero_en_i ? 1'd0 : 1'd0)), 
                .D4((hs_clk_zero_en_i ? 1'd0 : 1'd1)), 
                .D5((hs_clk_zero_en_i ? 1'd0 : 1'd0)), 
                .D6((hs_clk_zero_en_i ? 1'd0 : 1'd1)), 
                .D7((hs_clk_zero_en_i ? 1'd0 : 1'd0))) ; 
    // ================== AVANT ==================== //
    // DELAYE #(
    // .DEL_VALUE    (DELAYB_DEL_VALUE),
    // // .COARSE_DELAY (DELAYB_COARSE_DELAY),
    // .DEL_MODE     (DELAYB_DEL_MODE)
    // )
    // u_clk_90deg_delay (
    // .A            (clk_dif_w_oddr), 
    // .Z            (clk_dif_w)) ;   
    // ================== AVANT ==================== //
    MIPIA u_mipi_clk (.AP(lp_tx_clk_p_q2), 
                .AN(lp_tx_clk_n_q2), 
                .TP(1'b0),  //(~hs_tx_clk_en_q2), Updated due to DNG-12191
            .TN(1'b0),  //(~hs_tx_clk_en_q2),Updated due to DNG-12191
            .IHS(clk_dif_w), 
                .HSRXEN(1'd0), 
                .HSTXEN(hs_tx_clk_en_q2), 
                ///
            .OHS(), 
                .OLSP(), 
                .OLSN(), 
                ///
            .BP(clk_p_io), 
                .BN(clk_n_io)) ; 
    ///////////////////////////////////////////////////////////////////////////////
    /// Data
    ///////////////////////////////////////////////////////////////////////////////
    genvar i ; 
    generate
        for (i = 0;(i < NUM_LANE);i = (i + 1))
        begin : DATA_LINES
            // ================== AVANT ==================== //
            ODDRX4A #(.GSR("DISABLED")) u_data_serializer (.Q(data_dif_w[i]), 
                        .SCLK(eclkdiv_clk_4data_w),  // from u_eclkdiv_4data
                    .RST(gddr_reset_w), 
                        .ECLK(eclksync_clk_w),  // from u0_ECLKSYNC
                    .D0(hs_tx_data_i[((i * GEAR) + 0)]), 
                        .D1(hs_tx_data_i[((i * GEAR) + 1)]), 
                        .D2(hs_tx_data_i[((i * GEAR) + 2)]), 
                        .D3(hs_tx_data_i[((i * GEAR) + 3)]), 
                        .D4(hs_tx_data_i[((i * GEAR) + 4)]), 
                        .D5(hs_tx_data_i[((i * GEAR) + 5)]), 
                        .D6(hs_tx_data_i[((i * GEAR) + 6)]), 
                        .D7(hs_tx_data_i[((i * GEAR) + 7)])) ; 
            // ================== AVANT ==================== //
            MIPIA u_mipi_data (.AP(((i == 0) ? (lp_tx_data_p_q2[i] & (!lp_rx_en_i)) : lp_tx_data_p_q2[i])), 
                        .AN(((i == 0) ? (lp_tx_data_n_q2[i] & (!lp_rx_en_i)) : lp_tx_data_n_q2[i])), 
                        //.TP(1'b0),  //Updated due to DNG-12191 (hs_tx_en_q2 & ~lp_tx_data_en_q2 | lp_rx_en_i),
                    //.TN(1'b0),  //Updated due to DNG-12191 (hs_tx_en_q2 & ~lp_tx_data_en_q2 | lp_rx_en_i),
                    .TP(((i == 0) ? lp_rx_en_i : 1'b0)),  //0-TX,1-RX
                    .TN(((i == 0) ? lp_rx_en_i : 1'b0)),  //0-TX,1-RX 
                    .IHS(data_dif_w[i]), 
                        .HSRXEN(1'd0), 
                        .HSTXEN((hs_tx_en_q2 & (~(lp_tx_data_en_q2 | lp_rx_en_i)))), 
                        ///
                    .OHS(), 
                        .OLSP(lp_rx_data_p_w[i]), 
                        .OLSN(lp_rx_data_n_w[i]), 
                        ///
                    .BP(data_p_io[i]), 
                        .BN(data_n_io[i])) ; 
        end
    endgenerate
endmodule



