// Changes Made          : Added Skew Calibration support.
// =============================================================================
module csi2_transmitter_ip_ipgen_lscc_mipi_wrapper_tx #(parameter FAMILY = "LIFCL", 
        parameter DEVICE = "LIFCL-40", 
        parameter NUM_LANE = 1, 
        parameter GEAR = 8, 
        parameter [((4 * 8) - 1):0] INTF = "CSI2", 
        parameter [((7 * 8) - 1):0] DPHY_IP = "LATTICE", 
        parameter [((8 * 8) - 1):0] CLK_MODE = "HS_LP", 
        parameter [((12 * 8) - 1):0] DPHY_CIL_BYPASS = "CIL_BYPASSED", 
        parameter [((8 * 8) - 1):0] HSEL = "DISABLED", 
        parameter [((2 * 8) - 1):0] CIL_DATA_PREPARE = "01", 
        parameter [((6 * 8) - 1):0] CIL_DATA_TRAIL = "000001", 
        parameter [((6 * 8) - 1):0] CIL_DATA_ZERO = "000001", 
        parameter [((12 * 8) - 1):0] CIL_CLK_PREPARE = "1P0_TXCLKESC", 
        parameter [((5 * 8) - 1):0] CIL_CLK_TRAIL = "00001", 
        parameter [((7 * 8) - 1):0] CIL_CLK_ZERO = "0000001", 
        parameter INT_DATA_RATE = 500.0, 
        parameter TX_FREQ_TGT = 8'd112, 
        parameter REF_CLOCK_FREQ = 24, 
        parameter [((8 * 8) - 1):0] PLL_MODE = "INTERNAL", 
        parameter [((8 * 8) - 1):0] CM = "00000000", 
        parameter [((5 * 8) - 1):0] CN = "00000", 
        parameter [((3 * 8) - 1):0] CO = "000", 
        parameter DATA_WIDTH = (NUM_LANE * GEAR), 
        parameter LDW = ((DPHY_IP == "MIXEL") ? 4 : 8), 
        parameter LOW = ((DPHY_IP == "MIXEL") ? 5 : 8), 
        parameter DELAYB_DEL_VALUE = "0", 
        parameter DELAYB_COARSE_DELAY = "0NS", 
        parameter DELAYB_DEL_MODE = "NO_REG", 
        parameter CLK_HSZERO = 0, 
        parameter MODE = 0, 
        parameter IPI_CMP = 0, 
        parameter VOLTAGE = 0, 
        parameter CSET = 0, 
        parameter CRIPPLE = 0, 
        parameter IPP_CTRL = 0, 
        parameter IPP_SEL = 0, 
        parameter BW_CTL_BIAS = 0, 
        parameter V2I_PP_RES = 0, 
        parameter KP_VCO = 0, 
        parameter V2I_KVCO_SEL = 0, 
        parameter V2I_1V_EN = 0, 
        parameter CLKI_FREQ = 0, 
        parameter CLKOP_FREQ_ACTUAL = 0, 
        parameter CLKOS_FREQ_ACTUAL = 0, 
        parameter CLKOS2_FREQ_ACTUAL = 0, 
        parameter CLKOS3_FREQ_ACTUAL = 0, 
        parameter CLKOS4_FREQ_ACTUAL = 0, 
        parameter CLKOS5_FREQ_ACTUAL = 0, 
        parameter CLKOP_PHASE_ACTUAL = 0, 
        parameter CLKOS_PHASE_ACTUAL = 0, 
        parameter CLKOS2_PHASE_ACTUAL = 0, 
        parameter CLKOS3_PHASE_ACTUAL = 0, 
        parameter CLKOS4_PHASE_ACTUAL = 0, 
        parameter CLKOS5_PHASE_ACTUAL = 0, 
        parameter PLL_REFCLK_FROM_PIN = 0, 
        parameter IO_TYPE = 0, 
        parameter CLKI_DIVIDER_ACTUAL_STR = 0, 
        parameter FBCLK_DIVIDER_ACTUAL_STR = 0, 
        parameter FBK_MODE = 0, 
        parameter DIVOP_ACTUAL_STR = 0, 
        parameter DIVOS_ACTUAL_STR = 0, 
        parameter DIVOS2_ACTUAL_STR = 0, 
        parameter DIVOS3_ACTUAL_STR = 0, 
        parameter DIVOS4_ACTUAL_STR = 0, 
        parameter DIVOS5_ACTUAL_STR = 0, 
        parameter SSC_N_CODE_STR = 0, 
        parameter SSC_F_CODE_STR = 0, 
        parameter DELA = 0, 
        parameter DELB = 0, 
        parameter DELC = 0, 
        parameter DELD = 0, 
        parameter DELE = 0, 
        parameter DELF = 0, 
        parameter PHIA = 0, 
        parameter PHIB = 0, 
        parameter PHIC = 0, 
        parameter PHID = 0, 
        parameter PHIE = 0, 
        parameter PHIF = 0, 
        parameter FRAC_N_EN = 0, 
        parameter SS_EN = 0, 
        parameter CLKOP_BYPASS = 0, 
        parameter CLKOS_BYPASS = 0, 
        parameter CLKOS2_BYPASS = 0, 
        parameter CLKOS3_BYPASS = 0, 
        parameter CLKOS4_BYPASS = 0, 
        parameter CLKOS5_BYPASS = 0, 
        parameter CLKOS_EN = 0, 
        parameter CLKOS2_EN = 0, 
        parameter CLKOS3_EN = 0, 
        parameter CLKOS4_EN = 0, 
        parameter CLKOS5_EN = 0, 
        parameter DYN_PORTS_EN = 0, 
        parameter ENCLKOP_EN = 0, 
        parameter ENCLKOS_EN = 0, 
        parameter ENCLKOS2_EN = 0, 
        parameter ENCLKOS3_EN = 0, 
        parameter ENCLKOS4_EN = 0, 
        parameter ENCLKOS5_EN = 0, 
        parameter PLL_RST = 0, 
        parameter LOCK_EN = 0, 
        parameter PLL_LOCK_STICKY = 0, 
        parameter LEGACY_EN = 0, 
        parameter LMMI_EN = 0, 
        parameter APB_EN = 0, 
        parameter POWERDOWN_EN = 0, 
        parameter TRIM_EN_P = 0, 
        parameter TRIM_EN_S = 0, 
        parameter CLKOP_TRIM_MODE = 0, 
        parameter CLKOS_TRIM_MODE = 0, 
        parameter CLKOP_TRIM = 0, 
        parameter CLKOS_TRIM = 0) (
    // -----------------------------------------------------------------------------
    // Module Parameters
    // -----------------------------------------------------------------------------
    /// Configuration
    /// CIL Timing
    /// Alternative
    /// PLL
    /// INTERNAL
    /// DELAYB
    /// Soft PLL
    // -----------------------------------------------------------------------------
    // Input/Output Ports
    // -----------------------------------------------------------------------------
    // Clock and reset
    input wire sync_clk_i, 
    input wire sync_rst_i, 
    input wire reset_n_i,  //for byte_clk_o
    /// LMMI
    input wire lmmi_clk_i, 
    input wire lmmi_resetn_i, 
    input wire [(LDW - 1):0] lmmi_wdata_i, 
    input wire lmmi_wr_rdn_i, 
    input wire [(LOW - 1):0] lmmi_offset_i, 
    input wire lmmi_request_i, 
    output wire lmmi_ready_o, 
    output wire [(LDW - 1):0] lmmi_rdata_o, 
    output wire lmmi_rdata_valid_o, 
    // PLL outside of the Soft IP
    input wire pll_clkop_i, 
    input wire pll_clkos_i, 
    input wire pll_lock_i, 
    /// HS_TX
    input wire hs_tx_en_i, 
    input wire [(DATA_WIDTH - 1):0] hs_tx_data_i, 
    input wire [3:0] hs_tx_data_en_i, 
    input wire [3:0] tx_cil_word_valid_lane0_i, 
    input wire [3:0] tx_cil_word_valid_lane1_i, 
    input wire [3:0] tx_cil_word_valid_lane2_i, 
    input wire [3:0] tx_cil_word_valid_lane3_i, 
    input wire [7:0] clk_hszero_i, 
    /// Clock
    input wire hs_clk_en_i, 
    input wire hs_clk_zero_en_i, 
    /// LP_TX
    input wire [(NUM_LANE - 1):0] lp_tx_data_p_i, 
    input wire [(NUM_LANE - 1):0] lp_tx_data_n_i, 
    input wire lp_tx_data_en_i, 
    input wire lp_tx_clk_p_i, 
    input wire lp_tx_clk_n_i, 
    /// LP_RX
    input wire lp_rx_en_i, 
    output wire lp_rx_data_p_o, 
    output wire lp_rx_data_n_o, 
    /// Other
    input wire usrstdby_i, 
    input wire pd_dphy_i, 
    input wire txclk_hsgate_i, 
    output wire pll_lock_o, 
    output wire clk_byte_o, 
    output wire gddr_ready_o, 
    /// CIL
    output wire [(NUM_LANE - 1):0] data_lane_ss_o,  // Data line stop state
    output wire [(NUM_LANE - 1):0] hs_tx_cil_ready_o, 
    output wire hs_clk_cil_ready_o, 
    output wire cil_c2d_ready_o, 
    /// Skew-calibration signals 
    input wire skewcal_init_en_i, 
    input wire skewcal_period_en_i, 
    input wire [15:0] skewcal_init_i, 
    input wire [15:0] skewcal_period_i, 
    /// Tinitialization done signal
    input wire tinit_done_i, 
    /// DPHY
    inout wire clk_p_io, 
    inout wire clk_n_io, 
    inout wire [4:0] data_p_io, 
    inout wire [4:0] data_n_io) ;
    // -----------------------------------------------------------------------------
    // Local Parameters
    // -----------------------------------------------------------------------------
    localparam EMPTY = ((GEAR == 16) ? 16 : 24) ; 
    localparam DPHY_NUM_LANE = ((NUM_LANE == 4) ? "FOUR_LANES" : ((NUM_LANE == 3) ? "THREE_LANES" : ((NUM_LANE == 2) ? "TWO_LANES" : "ONE_LANE"))) ; 
    localparam DPHY_CLK_MODE = ((CLK_MODE == "HS_ONLY") ? "ENABLED" : "DISABLED") ; 
    localparam DPHY_DSI_CSI = ((INTF == "CSI2") ? "CSI2_APP" : "DSI_APP") ; 
    //Removed. This parameter is for DPHY RX only
    //localparam DPHY_DESKEW_EN = (INT_DATA_RATE > 1500)? "ENABLED" : "DISABLED"; // When operating at or below 1.5 Gbps, the transmission of initial Deskew sequence is optional.
    localparam DPHY_GEAR = ((GEAR == 8) ? "0b00" : ((GEAR == 16) ? "0b01" : ((GEAR == 32) ? "0b10" : ((GEAR == 64) ? "0b11" : "0b00")))) ; 
    localparam DPHY_HSEL = HSEL ; 
    localparam DPHY_PLL = ((PLL_MODE == "INTERNAL") ? "REGISTERED" : "BYPASSED") ; 
    localparam DPHY_CM = CM ; 
    localparam DPHY_CN = CN ; 
    localparam DPHY_CO = CO ; 
    localparam DIVIDER_COF = (((24 <= REF_CLOCK_FREQ) & (REF_CLOCK_FREQ <= 40)) ? 2 : (((41 <= REF_CLOCK_FREQ) & (REF_CLOCK_FREQ <= 60)) ? 3 : (((61 <= REF_CLOCK_FREQ) & (REF_CLOCK_FREQ <= 80)) ? 4 : (((81 <= REF_CLOCK_FREQ) & (REF_CLOCK_FREQ <= 100)) ? 5 : (((101 <= REF_CLOCK_FREQ) & (REF_CLOCK_FREQ <= 120)) ? 6 : (((121 <= REF_CLOCK_FREQ) & (REF_CLOCK_FREQ <= 140)) ? 7 : (((141 <= REF_CLOCK_FREQ) & (REF_CLOCK_FREQ <= 160)) ? 8 : (((161 <= REF_CLOCK_FREQ) & (REF_CLOCK_FREQ <= 180)) ? 9 : 10)))))))) ; 
    localparam TX_FREQ_PC = (1000 / TX_FREQ_TGT) ; 
    localparam REF_CLOCK_PER = (1000 / REF_CLOCK_FREQ) ; 
    localparam UI = (1000 / (TX_FREQ_TGT * GEAR)) ; 
    localparam LP00_DUR = 3 ; //(CIL_CLK_PREPARE == "1P0_TXCLKESC")? 2 : 2.5;
    localparam [4:0] COUNTER_VAL = (((60 + (4 * UI)) / REF_CLOCK_PER) + 5'd2) ; 
    // -----------------------------------------------------------------------------
    //FSM for Skew-calibration
    localparam ST_IDLE = 3'b000 ; 
    localparam ST_CLK_EN = 3'b001 ; 
    localparam ST_DAT_EN = 3'b010 ; 
    localparam ST_END_DAT = 3'b011 ; 
    localparam ST_END_CLK = 3'b100 ; 
    // -----------------------------------------------------------------------------
    // -----------------------------------------------------------------------------
    // Wire Declarations
    // -----------------------------------------------------------------------------
    wire [31:0] data_lane_0_w ; 
    wire [31:0] data_lane_1_w ; 
    wire [31:0] data_lane_2_w ; 
    wire [31:0] data_lane_3_w ; 
    wire [3:0] lp_tx_data_p_w ; 
    wire [3:0] lp_tx_data_n_w ; 
    wire [3:0] tx_word_valid_w ; 
    wire [3:0] hs_tx_cil_ready_w ; 
    wire tx_esc_clk_w ; 
    wire [3:0] data_lane_ss_w ; 
    wire pll_lock_w ; 
    wire cil_ready_w ; 
    wire [16:0] prepare_pass_w ; 
    //Added for Skew-calibration
    wire [3:0] skewcal_rdy_w ; 
    wire skewcal_data_rdy_w ; 
    wire skewcal_tx_cil_ready_w ; 
    reg [2:0] skewcal_state_r ; 
    reg [15:0] skewcal_counter_r ; 
    reg skewcal_ctr_done_r ; 
    reg skewcal_count_en_r ; 
    reg skewcal_dat_start_r ; 
    reg skewcal_done_r ; 
    reg skewcal_clk_start_r ; 
    reg ld_skewcal_init_r ; 
    reg ld_skewcal_period_r ; 
    reg ld_skewcal_clkprep_r ; 
    reg skewcal_period_en_r ; 
    reg [((GEAR * NUM_LANE) - 1):0] skewcal_pattern_r ; 
    assign skewcal_data_rdy_w = ((NUM_LANE == 2) ? (|skewcal_rdy_w[1:0]) : ((NUM_LANE == 3) ? (|skewcal_rdy_w[2:0]) : ((NUM_LANE == 4) ? (|skewcal_rdy_w[3:0]) : skewcal_rdy_w[0]))) ; 
    assign skewcal_tx_cil_ready_w = ((NUM_LANE == 2) ? (|hs_tx_cil_ready_w[1:0]) : ((NUM_LANE == 3) ? (|hs_tx_cil_ready_w[2:0]) : ((NUM_LANE == 4) ? (|hs_tx_cil_ready_w[3:0]) : hs_tx_cil_ready_w[0]))) ; 
    //END of update
    // -----------------------------------------------------------------------------
    //Added skewcal_done_r in cil_c2d_ready_o condition
    //Wait for skew calibration to be done
    // -----------------------------------------------------------------------------
    assign cil_c2d_ready_o = ((CLK_MODE == "HS_LP") ? (cil_ready_w && skewcal_done_r) : (data_lane_ss_w && skewcal_done_r)) ; 
    assign pll_lock_w = ((PLL_MODE == "INTERNAL") ? pll_lock_o : pll_lock_i) ; 
    assign prepare_pass_w = (((LP00_DUR * DIVIDER_COF) + ((262 + (CLK_HSZERO * TX_FREQ_PC)) / REF_CLOCK_PER)) + 20) ; 
    reg [(DATA_WIDTH - 1):0] hs_tx_data_q ; 
    reg [(NUM_LANE - 1):0] lp_tx_data_p_q ; 
    reg [(NUM_LANE - 1):0] lp_tx_data_n_q ; 
    reg hs_tx_en_q ; 
    (* syn_keep=1 *) reg hs_clk_en_q ; 
    reg hs_clk_zero_en_q ; 
    reg lp_tx_data_en_q ; 
    reg lp_tx_clk_p_q ; 
    reg lp_tx_clk_n_q ; 
    reg [3:0] hs_tx_data_en_q ; 
    always
        @(posedge clk_byte_o or 
            negedge reset_n_i)
        begin
            if ((!reset_n_i)) 
                begin
                    hs_tx_en_q <=  1'd0 ;
                    hs_clk_en_q <=  1'd0 ;
                    hs_clk_zero_en_q <=  1'd0 ;
                    lp_tx_data_en_q <=  1'd1 ;
                    lp_tx_clk_p_q <=  1'd1 ;
                    lp_tx_clk_n_q <=  1'd1 ;
                    hs_tx_data_en_q <=  4'd0 ;
                    hs_tx_data_q <=  {DATA_WIDTH{1'b1}} ;
                    lp_tx_data_p_q <=  {NUM_LANE{1'b1}} ;
                    lp_tx_data_n_q <=  {NUM_LANE{1'b1}} ;
                end
            else
                begin
                    hs_tx_en_q <=  hs_tx_en_i ;
                    hs_clk_en_q <=  hs_clk_en_i ;
                    hs_clk_zero_en_q <=  hs_clk_zero_en_i ;
                    lp_tx_data_en_q <=  lp_tx_data_en_i ;
                    lp_tx_clk_p_q <=  lp_tx_clk_p_i ;
                    lp_tx_clk_n_q <=  lp_tx_clk_n_i ;
                    hs_tx_data_q <=  hs_tx_data_i ;
                    hs_tx_data_en_q <=  hs_tx_data_en_i ;
                    lp_tx_data_p_q <=  lp_tx_data_p_i ;
                    lp_tx_data_n_q <=  lp_tx_data_n_i ;
                end
        end
    /// Internal reset / Davit
    // reg pll_lock_r;
    // reg pd_dphy_int;
    // assign pd_dphy_int = (pll_lock_o & !pll_lock_r);
    // always @(posedge sync_clk_i or posedge sync_rst_i) begin
    // if (sync_rst_i == 1'd1) begin
    // pll_lock_r  <= 0;
    // pd_dphy_int <= 0;
    // end
    // else begin
    // pll_lock_r  <= pll_lock_o;
    // pd_dphy_int <= (pll_lock_o & !pll_lock_r);
    // end
    // end
    ///Davit/// HS_TRAIL in process (used for CIL mode only to turn off clock lane after turning off data lines)
    reg [4:0] counter ; 
    reg hs_tx_en_r ; 
    (* syn_keep=1 *) reg hs_clk_en_r ; 
    reg hs_tx_data_en_r ; 
    reg hs_clk_cil_ready_r ; 
    reg [16:0] prepare_pass_r ; 
    assign data_lane_ss_o = data_lane_ss_w[(NUM_LANE - 1):0] ; 
    always
        @(posedge sync_clk_i or 
            posedge sync_rst_i)
        begin
            /// Used for bounces
            if ((sync_rst_i == 1'd1)) 
                begin
                    hs_clk_en_r <=  0 ;
                end
            else
                begin
                    hs_clk_en_r <=  hs_clk_en_q ;
                end
        end
    always
        @(posedge sync_clk_i or 
            posedge sync_rst_i)
        begin
            if ((sync_rst_i == 1'd1)) 
                begin
                    hs_tx_en_r <=  1'd0 ;
                end
            else
                begin
                    hs_tx_en_r <=  hs_tx_en_i ;
                end
        end
    // -----------------------------------------------------------------------------
    // Assign Statement
    // -----------------------------------------------------------------------------
    assign tx_word_valid_w = ((GEAR == 16) ? 4'b0011 : 4'b0001) ; /// Now we support 8 and 16
    /// For CIL_BYPASSED
    assign hs_tx_cil_ready_o[(NUM_LANE - 1):0] = ((DPHY_CIL_BYPASS == "CIL_BYPASSED") ? {NUM_LANE{1'd1}} : hs_tx_cil_ready_w[(NUM_LANE - 1):0]) ; /// For CIL_ENABLED
    assign hs_clk_cil_ready_o = hs_clk_cil_ready_r ; ////TEEEESSSSSTTTTT
    // -----------------------------------------------------------------------------
    // Generate Assign Statements
    // -----------------------------------------------------------------------------
    generate
        if ((DPHY_IP == "MIXEL")) 
            begin : LP_TX_DATA_CONN
                if ((NUM_LANE > 0)) 
                    begin : genblk1
                        assign data_lane_0_w = {{EMPTY{1'd0}},
                                    hs_tx_data_i[((1 * GEAR) - 1):(0 * GEAR)]} ; 
                        assign lp_tx_data_p_w[0] = lp_tx_data_p_i[0] ; 
                        assign lp_tx_data_n_w[0] = lp_tx_data_n_i[0] ; 
                    end
                if ((NUM_LANE > 1)) 
                    begin : genblk2
                        assign data_lane_1_w = {{EMPTY{1'd0}},
                                    hs_tx_data_i[((2 * GEAR) - 1):(1 * GEAR)]} ; 
                        assign lp_tx_data_p_w[1] = lp_tx_data_p_i[1] ; 
                        assign lp_tx_data_n_w[1] = lp_tx_data_n_i[1] ; 
                    end
                else
                    begin : genblk2
                        assign data_lane_1_w = 32'hFFFFFFFF ; //Add to meet requirement from "Synplify Pro"
                    end
                if ((NUM_LANE > 2)) 
                    begin : genblk3
                        assign data_lane_2_w = {{EMPTY{1'd0}},
                                    hs_tx_data_i[((3 * GEAR) - 1):(2 * GEAR)]} ; 
                        assign lp_tx_data_p_w[2] = lp_tx_data_p_i[2] ; 
                        assign lp_tx_data_n_w[2] = lp_tx_data_n_i[2] ; 
                    end
                else
                    begin : genblk3
                        assign data_lane_2_w = 32'hFFFFFFFF ; //Add to meet requirement from "Synplify Pro"
                    end
                if ((NUM_LANE > 3)) 
                    begin : genblk4
                        assign data_lane_3_w = {{EMPTY{1'd0}},
                                    hs_tx_data_i[((4 * GEAR) - 1):(3 * GEAR)]} ; 
                        assign lp_tx_data_p_w[3] = lp_tx_data_p_i[3] ; 
                        assign lp_tx_data_n_w[3] = lp_tx_data_n_i[3] ; 
                    end
                else
                    begin : genblk4
                        assign data_lane_3_w = 32'hFFFFFFFF ; //Add to meet requirement from "Synplify Pro"
                    end
            end
    endgenerate
    always
        @(posedge sync_clk_i or 
            posedge sync_rst_i)
        begin
            if ((sync_rst_i == 1'd1)) 
                begin
                    hs_clk_cil_ready_r <=  1'd0 ;
                    prepare_pass_r <=  4'd0 ;
                end
            else
                begin
                    if ((!hs_clk_en_i)) 
                        begin
                            hs_clk_cil_ready_r <=  1'd0 ;
                            prepare_pass_r <=  prepare_pass_w ;
                        end
                    else
                        begin
                            if ((cil_ready_w == 1'b1)) 
                                begin
                                    hs_clk_cil_ready_r <=  1'd0 ;
                                end
                            else
                                begin
                                    if ((prepare_pass_r == 0)) 
                                        begin
                                            hs_clk_cil_ready_r <=  1'd1 ;
                                        end
                                    else
                                        begin
                                            prepare_pass_r <=  (prepare_pass_r - 1'd1) ;
                                            hs_clk_cil_ready_r <=  1'd0 ;
                                        end
                                end
                        end
                end
        end
    // -----------------------------------------------------------------------------
    //SKEW CALIBRATION SEQUENCE - FOR CIL_ENABLED configuration
    // -----------------------------------------------------------------------------
    always
        @(posedge clk_byte_o or 
            negedge reset_n_i)
        begin
            if ((!reset_n_i)) 
                begin
                    skewcal_state_r <=  ST_IDLE ;
                    skewcal_clk_start_r <=  1'b0 ;
                    skewcal_done_r <=  1'b0 ;
                    skewcal_count_en_r <=  1'b0 ;
                    ld_skewcal_init_r <=  1'b0 ;
                    ld_skewcal_clkprep_r <=  1'b0 ;
                    ld_skewcal_period_r <=  1'b0 ;
                    skewcal_dat_start_r <=  1'b0 ;
                    skewcal_period_en_r <=  1'b0 ;
                    skewcal_pattern_r <=  'h0 ;
                end
            else
                begin
                    case (skewcal_state_r)
                    ST_IDLE : 
                        //IDLE State
                        begin
                            // Get out of IDLE when initial skew calibration
                            // is ENABLED and has not yet started 
                            if (tinit_done_i) 
                                begin
                                    if (((skewcal_init_en_i && pll_lock_w) && cil_ready_w)) 
                                        begin
                                            //Modified 01/2021
                                            if ((!skewcal_done_r)) 
                                                begin
                                                    //Start HS clock
                                                    skewcal_clk_start_r <=  1'b1 ;
                                                    skewcal_count_en_r <=  1'b1 ;
                                                    ld_skewcal_clkprep_r <=  1'b1 ;
                                                    skewcal_state_r <=  ST_CLK_EN ;
                                                end
                                            else
                                                begin
                                                    skewcal_clk_start_r <=  1'b0 ;
                                                    skewcal_state_r <=  ST_IDLE ;
                                                end
                                        end
                                    else
                                        begin
                                            //Always set to 1 when initial deskew calibration is not enabled
                                            skewcal_done_r <=  1'b1 ;
                                            skewcal_state_r <=  ST_IDLE ;
                                        end
                                end
                            //Periodic skew calibration
                            if (tinit_done_i) 
                                begin
                                    if (((skewcal_period_en_i && pll_lock_w) && cil_ready_w)) 
                                        begin
                                            //Modified 01/2021
                                            //Start HS clock
                                            skewcal_done_r <=  1'b0 ;
                                            skewcal_period_en_r <=  1'b1 ;//used this flag to distinguish between tskewcal_init and tskewcal_period counter
                                            skewcal_clk_start_r <=  1'b1 ;
                                            skewcal_count_en_r <=  1'b1 ;
                                            ld_skewcal_clkprep_r <=  1'b1 ;
                                            skewcal_state_r <=  ST_CLK_EN ;
                                        end
                                end
                        end
                    ST_CLK_EN : 
                        //HS clock enabled State
                        begin
                            ld_skewcal_clkprep_r <=  1'b0 ;
                            //Wait for HS clock to be ready
                            if (skewcal_ctr_done_r) 
                                begin
                                    skewcal_count_en_r <=  1'b1 ;
                                    // Enable HS data
                                    skewcal_dat_start_r <=  1'b1 ;
                                    skewcal_state_r <=  ST_DAT_EN ;
                                end
                            else
                                begin
                                    skewcal_dat_start_r <=  1'b0 ;
                                    skewcal_state_r <=  ST_CLK_EN ;
                                end
                        end
                    ST_DAT_EN : 
                        //HS Skew calibration enabled State
                        begin
                            //Wait for CIL TX to be ready
                            if (skewcal_tx_cil_ready_w) 
                                /*(skewcal_data_rdy_w)*/
                                begin
                                    //Enable counter
                                    skewcal_count_en_r <=  1'b1 ;
                                    skewcal_pattern_r <=  {(GEAR * NUM_LANE){1'b1}} ;//skewcal_sync
                                    if ((!skewcal_period_en_r)) 
                                        begin
                                            //Start counting tskewcal_init
                                            ld_skewcal_init_r <=  1'b1 ;
                                        end
                                    else
                                        begin
                                            //Start counting tskewcal_period
                                            ld_skewcal_period_r <=  1'b1 ;
                                        end
                                    skewcal_state_r <=  ST_END_DAT ;
                                end
                            else
                                begin
                                    skewcal_state_r <=  ST_DAT_EN ;
                                end
                        end
                    ST_END_DAT : 
                        begin
                            ld_skewcal_init_r <=  1'b0 ;
                            ld_skewcal_period_r <=  1'b0 ;
                            skewcal_pattern_r <=  64'hAAAA_AAAA_AAAA_AAAA ;
                            if (skewcal_ctr_done_r) 
                                begin
                                    skewcal_pattern_r <=  {(GEAR * NUM_LANE){1'b0}} ;
                                    skewcal_count_en_r <=  1'b0 ;
                                    skewcal_dat_start_r <=  1'b0 ;
                                    skewcal_state_r <=  ST_END_CLK ;
                                end
                            else
                                begin
                                    skewcal_state_r <=  ST_END_DAT ;
                                end
                        end
                    ST_END_CLK : 
                        begin
                            skewcal_done_r <=  1'b1 ;
                            skewcal_clk_start_r <=  1'b0 ;
                            skewcal_state_r <=  ST_IDLE ;
                        end
                    endcase 
                end
        end
    //Counter for skew calibration sequence
    always
        @(posedge clk_byte_o or 
            negedge reset_n_i)
        begin
            if ((!reset_n_i)) 
                begin
                    skewcal_counter_r <=  6'd0 ;
                end
            else
                begin
                    if (skewcal_count_en_r) 
                        begin
                            case (1'b1)
                            ld_skewcal_init_r : 
                                skewcal_counter_r <=  skewcal_init_i ;
                            ld_skewcal_period_r : 
                                skewcal_counter_r <=  skewcal_period_i ;
                            ld_skewcal_clkprep_r : 
                                skewcal_counter_r <=  prepare_pass_w ;
                            default : 
                                skewcal_counter_r <=  (skewcal_counter_r - 1'b1) ;
                            endcase 
                        end
                    else
                        begin
                            skewcal_counter_r <=  6'd0 ;
                        end
                end
        end
    always
        @(*)
        begin
            skewcal_ctr_done_r = (skewcal_counter_r == 6'd1) ;
        end
    // -----------------------------------------------------------------------------
    //END of update
    // -----------------------------------------------------------------------------
    generate
        if ((DPHY_IP == "MIXEL")) 
            begin : MIXEL_HARD_IP
                if ((DPHY_CIL_BYPASS == "CIL_BYPASSED")) 
                    begin : CIL_BYPASSED_DPHY
                        DPHY #(.GSR("DISABLED"),
                                .AUTO_PD_EN("POWERED_UP"),
                                .CFG_NUM_LANES(DPHY_NUM_LANE),
                                .CM({"0b",
                                    DPHY_CM}),
                                .CN({"0b",
                                    DPHY_CN}),
                                .CO({"0b",
                                    DPHY_CO}),
                                .CONT_CLK_MODE(DPHY_CLK_MODE),
                                .DESKEW_EN("DISABLED"),
                                .DSI_CSI(DPHY_DSI_CSI),
                                .EN_CIL(DPHY_CIL_BYPASS),
                                .HSEL(DPHY_HSEL),
                                .LANE0_SEL("LANE_0"),
                                .LOCK_BYP("GATE_TXBYTECLKHS"),
                                .MASTER_SLAVE("MASTER"),
                                .PLLCLKBYPASS(DPHY_PLL),
                                .RSEL("0b01"),
                                .RXCDRP("0b00"),
                                .RXDATAWIDTHHS("0b01"),
                                .RXLPRP("0b000"),
                                .TEST_ENBL("0b000000"),
                                .TEST_PATTERN("0b00000000000000000000000000000000"),
                                .TST("0b1001"),
                                .TXDATAWIDTHHS(DPHY_GEAR),
                                .U_PRG_HS_PREPARE("0b01"),
                                .U_PRG_HS_TRAIL("0b000001"),
                                .U_PRG_HS_ZERO("0b000001"),
                                .U_PRG_RXHS_SETTLE("0b000001"),
                                .UC_PRG_HS_PREPARE("1P0_TXCLKESC"),
                                .UC_PRG_HS_TRAIL("0b00001"),
                                .UC_PRG_HS_ZERO("0b0000001"),
                                .UC_PRG_RXHS_SETTLE("0b000001")) u_DPHY_NO_CIL_tx (// Global set reset
                                // Powers down or driving LP-11 on inactive lanes reported by CFG_NUM_LANES parameter.
                                // Sets the number of active lanes` "FOUR_LANES", ... , "ONE_LANE".
                                // PLL dividers should be set to produce the required high speed BITCLK to be used for testing.
                                // PLL dividers should be set to produce the required high speed BITCLK to be used for testing.
                                // PLL dividers should be set to produce the required high speed BITCLK to be used for testing.
                                // Clock mode which can be continuous(Only HS mode) or noncontinuous(HS and LP mode).
                                //(DPHY_DESKEW_EN),                                    // Enables Deskew feature that modifies ERRSYNC/NOSYNC behavior
                                // Set "CSI2_APP" for CSI2 and "DSI_APP" for DSI.
                                // Set to "CIL_ENABLED" for PHY operates with CIL enabled.
                                // Set to "DISABLED" for 1.5Gbps operation and below,Set to "ENABLED" for 2.5Gbps operation.
                                // This parameter determines which lane will act as data lane0 in HS Operation mode.
                                // "GATE_TXBYTECLKHS"` PLL LOCK signal will gate TxWordClkHS clock."NOT_GATE_TXBYTECLKHS"` CIL based counter will be used to gate the TxWordClkHS.
                                // Should be set to "MASTER" for HS-TX and LP-TX Tests and set to "SLAVE" for remaining tests.
                                // When BYPASSED maybe PLL doesn't work.
                                // On-chip termination control bits for manual calibration of HS-RX.
                                // RX_GEAR.
                                // High-Speed Receive Data Width Select.
                                // One-time programming bits that adjust the threshold voltage of LP-CD.
                                // PLL charge pump current control
                                //
                                // High-Speed Transmit Data Width Select or GEAR.
                                // Bit used to program T_CLK_PREPARE time in the beginning of high speed transmission mode.
                                // Bits used to program T_CLK_TRAIL time in the end of high speed transmission mode.
                                // Bits used to program T_CLK_ZERO time in the beginning of high speed transmission mode.
                                // Bits used to program T_HS_SETTLE. HS-RX waits for Time-out T_HS_SETTLE in order to neglect transition effects
                                // IN
                                // LMMI
                                .LMMICLK(lmmi_clk_i),  // Clock for LMMI.
                                .LMMIRESET_N(lmmi_resetn_i),  // Active low reset.
                                .LMMIREQUEST(lmmi_request_i),  // Request.
                                .LMMIWRRD_N(lmmi_wr_rdn_i),  // Active hight write, low read.
                                .LMMIOFFSET(lmmi_offset_i),  // Offset.
                                .LMMIWDATA(lmmi_wdata_i),  // Data from user.
                                // Clock and reset
                                .BITCKEXT(((DPHY_PLL == "REGISTERED") ? 1'd1 : pll_clkop_i)),  // Maybe Bit clock external.
                                .CLKREF(sync_clk_i),  // Reference clock to PLL.
                                .PDDPHY((pd_dphy_i || (!pll_lock_w))),  // Power down DPHY.
                                .PDPLL(((DPHY_PLL == "REGISTERED") ? (usrstdby_i || sync_rst_i) : 1'd1)),  // Power down PLL.
                                // Scan mode
                                .SCCLKIN(1'd1),  // Scan clock in.
                                // HS_TX enable ports
                                .UCENCK((hs_clk_en_q || hs_clk_en_r)),  // Clock  HS_TX enable.
                                .UED0THEN(((NUM_LANE > 0) ? hs_tx_en_q : 1'b0)),  // Lane 0 HS_TX enable.
                                .U1ENTHEN(((NUM_LANE > 1) ? hs_tx_en_q : 1'b0)),  // Lane 1 HS_TX enable.
                                .U3END3(((NUM_LANE > 3) ? hs_tx_en_q : 1'b0)),  // lane 3 HS_TX enable.
                                .U2END2(((NUM_LANE > 2) ? hs_tx_en_q : 1'b0)),  // lane 2 HS_TX enable.
                                // HS_TX ports
                                .UTXDHS({{(32 - GEAR){1'd0}},
                                        hs_tx_data_q[((1 * GEAR) - 1):(0 * GEAR)]}),  // Lane 0 HS_TX data.
                                .U1TXDHS(((NUM_LANE > 1) ? {{(32 - GEAR){1'd0}},
                                        hs_tx_data_q[((2 * GEAR) - 1):(1 * GEAR)]} : 32'hFFFF_FFFF)),  // Lane 1 HS_TX data.
                                .U2TXDHS(((NUM_LANE > 2) ? {{(32 - GEAR){1'd0}},
                                        hs_tx_data_q[((3 * GEAR) - 1):(2 * GEAR)]} : 32'hFFFF_FFFF)),  // Lane 2 HS_TX data.
                                .U3TXDHS(((NUM_LANE > 3) ? {{(32 - GEAR){1'd0}},
                                        hs_tx_data_q[((4 * GEAR) - 1):(3 * GEAR)]} : 32'hFFFF_FFFF)),  // Lane 3 HS_TX data.
                                // HS_TX word valid ports
